select id, stu_no, stu_name, gender, age, class_name, height, weight, score from stu_info
and ( stu_no like concat('%', #{keyword}, '%') or stu_name like concat('%', #{keyword}, '%') )
order by id desc limit #{pageSize} offset #{offset}

select id, stu_no, stu_name, gender, age, class_name, height, weight, score
from stu_info
where stu_no = #{stuNo}
